from flask import Flask, request, jsonify
import psycopg2
from psycopg2.extras import RealDictCursor
import logging

app = Flask(__name__)

# Database configuration
DB_CONFIG = {
    'host': 'localhost',
    'database': 'analytics_db',
    'user': 'analytics_user',
    'password': 'analytics_password',
    'port': 5432
}

def get_db_connection():
    return psycopg2.connect(**DB_CONFIG)

def validate_table_name(table_name):
    # Basic validation to prevent SQL injection
    if not table_name or not table_name.replace('_', '').isalnum():
        raise ValueError("Invalid table name")
    return table_name

def validate_column_names(columns):
    # Basic validation to prevent SQL injection
    if not columns:
        return []
    validated_columns = []
    for col in columns:
        if col and col.replace('_', '').isalnum():
            validated_columns.append(col)
    return validated_columns

def build_select_query(table_name, columns=None, filters=None):
    table_name = validate_table_name(table_name)
    
    if columns:
        columns = validate_column_names(columns)
        if not columns:
            columns = ['*']
        select_clause = ', '.join(columns)
    else:
        select_clause = '*'
    
    query = f"SELECT {select_clause} FROM {table_name}"
    
    if filters:
        where_conditions = []
        params = []
        for key, value in filters.items():
            if key and key.replace('_', '').isalnum():
                where_conditions.append(f"{key} = %s")
                params.append(value)
        
        if where_conditions:
            query += " WHERE " + " AND ".join(where_conditions)
            return query, params
    
    return query, None

@app.route('/api/query', methods=['POST'])
def execute_query():
    try:
        data = request.get_json()
        
        if not data:
            return jsonify({'error': 'No data provided'}), 400
            
        table_name = data.get('table')
        columns = data.get('columns')
        filters = data.get('filters')
        
        if not table_name:
            return jsonify({'error': 'Table name is required'}), 400
        
        query, params = build_select_query(table_name, columns, filters)
        
        conn = get_db_connection()
        cursor = conn.cursor(cursor_factory=RealDictCursor)
        cursor.execute(query, params)
        results = cursor.fetchall()
        cursor.close()
        conn.close()
        
        return jsonify({
            'success': True,
            'data': [dict(row) for row in results],
            'count': len(results)
        })
        
    except ValueError as ve:
        return jsonify({'error': str(ve)}), 400
    except psycopg2.Error as db_error:
        return jsonify({'error': 'Database error occurred'}), 500
    except Exception as e:
        logging.error(f"Unexpected error: {str(e)}")
        return jsonify({'error': 'An unexpected error occurred'}), 500

@app.route('/api/table/<table_name>/columns', methods=['GET'])
def get_table_columns(table_name):
    try:
        table_name = validate_table_name(table_name)
        
        conn = get_db_connection()
        cursor = conn.cursor(cursor_factory=RealDictCursor)
        
        query = """
        SELECT column_name, data_type 
        FROM information_schema.columns 
        WHERE table_name = %s 
        ORDER BY ordinal_position
        """
        cursor.execute(query, (table_name,))
        results = cursor.fetchall()
        cursor.close()
        conn.close()
        
        return jsonify({
            'success': True,
            'columns': [dict(row) for row in results]
        })
        
    except ValueError as ve:
        return jsonify({'error': str(ve)}), 400
    except psycopg2.Error as db_error:
        return jsonify({'error': 'Database error occurred'}), 500
    except Exception as e:
        logging.error(f"Unexpected error: {str(e)}")
        return jsonify({'error': 'An unexpected error occurred'}), 500

@app.route('/api/tables', methods=['GET'])
def get_tables():
    try:
        conn = get_db_connection()
        cursor = conn.cursor(cursor_factory=RealDictCursor)
        
        query = """
        SELECT table_name 
        FROM information_schema.tables 
        WHERE table_schema = 'public'
        ORDER BY table_name
        """
        cursor.execute(query)
        results = cursor.fetchall()
        cursor.close()
        conn.close()
        
        return jsonify({
            'success': True,
            'tables': [row['table_name'] for row in results]
        })
        
    except psycopg2.Error as db_error:
        return jsonify({'error': 'Database error occurred'}), 500
    except Exception as e:
        logging.error(f"Unexpected error: {str(e)}")
        return jsonify({'error': 'An unexpected error occurred'}), 500

